              fontSize: "14px",
              padding: 0,
              display: "flex",
              alignItems: "center",
              gap: "4px",
            }}
          >
            ← Back to Projects
          </button>
        </div>

        <ProjectHeader
          project={selectedProject}
          phases={phases}
          onSave={handleSaveProject}
          onCancel={() => setSelectedProject(null)}
        />

        <div style={{ padding: "12px 16px 4px", fontWeight: 600, fontSize: "13px", color: "#374151" }}>
          Phases
        </div>
        <PhaseList phases={phases} />
      </div>
    );
  }

  // List view
  return (
    <div style={{ fontFamily: "system-ui, sans-serif", height: "100%" }}>
      <div style={{
        padding: "12px 16px",
        borderBottom: "1px solid #e5e7eb",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
      }}>
        <span style={{ fontWeight: 700, fontSize: "16px", color: "#111827" }}>
          Development Department
        </span>
        <button
          onClick={handleCreateProject}
          style={{
            padding: "6px 14px",
            backgroundColor: "#2563eb",
            color: "#fff",
            border: "none",
            borderRadius: "6px",
            cursor: "pointer",
            fontSize: "13px",
            fontWeight: 500,
          }}
        >
          + Create Project
        </button>
      </div>

      {projects.length === 0 ? (
        <div style={{ padding: "32px 16px", textAlign: "center", color: "#9ca3af", fontSize: "14px" }}>
          No projects yet. Click "Create Project" to get started.
        </div>
      ) : (
        <div style={{ padding: "8px" }}>
          {projects.map((project) => (
            <div
              key={project.id}
              onClick={() => setSelectedProject(project)}
              style={{
                padding: "12px",
                border: "1px solid #e5e7eb",
                borderRadius: "8px",
                marginBottom: "6px",
                cursor: "pointer",
                backgroundColor: "#fff",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                transition: "border-color 0.15s",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.borderColor = "#93c5fd")}
              onMouseLeave={(e) => (e.currentTarget.style.borderColor = "#e5e7eb")}
            >
              <div>
                <div style={{ fontWeight: 600, fontSize: "14px", color: "#111827" }}>
                  {project.name}
                </div>
                {project.objective && (
                  <div style={{ fontSize: "12px", color: "#6b7280", marginTop: "2px" }}>
                    {project.objective}
                  </div>
                )}
              </div>
              <StatusBadge status={project.status} />
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

